  ('social-worker-moex-07915', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織經營為求更高的競爭力，組織必須改變傳統的經營與管理的方式，下列那一項是正確的？', '["必須強調嚴格的指揮系統來制定決策", "使用傳統金字塔型的組織結構，才能掌握組織發展", "新型的組織中，管理者必須依賴地位、頭銜及職權才能達成任務", "發展無疆界組織（boundaryless organization），增加員工與相關人員互動"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "a6c91d4ef579", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
